var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"그래, 너도 우리의 자매가 되고 싶어진 건가?","JPN":"そうか、お前も私たちの姉妹になりたくなったのか？","ENG":"Ah, do you wish to join our sisterhood?","TWN":"你也想成為我們的姐妹嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"물론 재조립의 과정은 고통스럽지.","JPN":"もちろん、再成形の過程は苦しい。","ENG":"Granted, reassembly can be an agonizing process.","TWN":"當然，重新組裝的過程異常痛苦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"그리고 그 아픔은 아주 잠깐이야.","JPN":"だが、その痛みはほんの一瞬だ。","ENG":"But the pain will be brief.","TWN":"但那痛苦非常短暫。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"신경이 보채는 말초적인 비명을 참고 나면, 그 후에는 영원한 즐거움이 찾아오거든.","JPN":"末梢神経の悲鳴を我慢すると、その後は永遠の楽しみが訪れる。","ENG":"Once you've manage to swallow your blood-curdling screams, you shall be met with eternal ecstasy.","TWN":"只需要忍過那撕心裂肺的過程，接下來就會獲得永遠的快樂。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"꾸며낸 말은 아니야. 예전의 나도 직접 겪어 봤으니까.","JPN":"大袈裟な表現ではない。かつて私も直接経験したのだからな。","ENG":"I'm not making this up. I've been through this myself.","TWN":"不是瞎編的謊話，因為以前我也親身經歷過。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"고통에 못 이겨 금방이라도 경기를 일으킬 것 같으면서도...... 끝까지 참아냈단다.","JPN":"苦しみに耐え切れず、すぐにでも発作を起こしそうになっても……最後まで耐え抜いた。","ENG":"The pain was so acute that it made my body convulse uncontrollably… but I withstood it all to the end.","TWN":"差點因為無法忍受痛苦而昏厥……但還是忍耐到了最後。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"한심한 인간이었지만, 그 덕분에 지금의 내가 존재할 수 있었던 거지.","JPN":"情けない人間だったが、そのおかげで今の私が存在することができた。","ENG":"I was once a pathetic mortal, but enduring such tribulations has made me who I am today.","TWN":"雖然之前是個可憐的人類，但也正因如此，才有了現在的我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"......후훗. 자매가 될 마음은 없다고?","JPN":"……フフッ。姉妹になる気はないだと？","ENG":"... Pfft. So you do not wish to become a sister?","TWN":"……呼呼，不想成為我們的姐妹？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"그러면서 나와 마지막까지 함께하겠다니, 자기가 얼마나 무모한 이야기를 하는지 알고는 있는 걸까.","JPN":"その気もないくせに、私と最後までともにすると言い出すとは。\\n今自分がどれだけ無謀なことを言ったかわかるか。","ENG":"Yet you still insist you will stand by me till the very end. Do you realize what a reckless venture that would be?","TWN":"那還說什麼要和我一起走到最後，你知道自己有多麼魯莽嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"하지만...... 예전의 나라면 너처럼 대범한 사람을 탐했을지도 모르겠네.","JPN":"しかし……以前の私だったら、お前のような大胆な人間を欲したのかもしれない。","ENG":"However… Perhaps the old me would have coveted a bold one like you.","TWN":"但是……如果是以前的我，可能會喜歡像你這樣豁達的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"그녀가 내 안에서 완전히 사라지기 전까지, 흉내를 내 볼까.","JPN":"彼女が私の中から完全に消えないうちに、真似をしてみるか。","ENG":"I suppose I could play pretend until she completely dissipates from within.","TWN":"在那個女人還沒在我身體裡完全消失之前，我來模仿一下她吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_NULL","text":{"KOREA":"결국 이것도 그녀가 저질렀던 한순간의 변덕에 불과하겠지만.","JPN":"結局これも、彼女が起こした一瞬の気まぐれにすぎないのだろうが。","ENG":"Though this would amount to no more than one of those fleeting whims she was prone to.","TWN":"歸根結底，這也只不過是她曾經所決定的事，瞬間變卦而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};